// TenantMiddleware extracts and validates tenant from authenticated session
func TenantMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Extract tenant ID from verified JWT claims (NOT from URL!)
		tenantID, err := getTenantFromAuthenticatedSession(r)
		if err != nil {
			log.Printf("SECURITY: Invalid tenant access attempt from %s", r.RemoteAddr)
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		// Store tenant ID in request context for downstream handlers
		ctx := context.WithValue(r.Context(), tenantContextKey, tenantID)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

// getTenantIDFromContext safely retrieves tenant ID from context
func getTenantIDFromContext(ctx context.Context) (int, bool) {
	tenantID, ok := ctx.Value(tenantContextKey).(int)
	return tenantID, ok
