Cross-tenant access introduces significant risk and requires explicit, auditable authorization with multiple safeguards. Here's a production-ready pattern.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strconv"
	"sync"
	"time"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

var db *sql.DB

type contextKey string

const (
	userContextKey   contextKey = "user"
	tenantContextKey contextKey = "tenant_id"
)

type Role string

const (
	RoleTenantUser  Role = "tenant_user"
	RoleTenantAdmin Role = "tenant_admin"
	RoleSuperAdmin  Role = "super_admin"
)

type User struct {
	ID              int
	Email           string
	TenantID        int
	Role            Role
	AllowedTenants  []int // For cross-tenant access
	CrossTenantRole Role  // Limited role when accessing other tenants
}

type TenantPermission struct {
	TargetTenantID int
	Permissions    []string
	ExpiresAt      time.Time
}

type AuditLog struct {
	Timestamp      time.Time
	UserID         int
	SourceTenantID int
	TargetTenantID int
	Action         string
	Resource       string
	ResourceID     string
	IPAddress      string
	UserAgent      string
	Success        bool
	Reason         string
}

var auditLogger = &AuditLogger{}

type AuditLogger struct {
	mu   sync.Mutex
	logs []AuditLog
}

func (a *AuditLogger) Log(entry AuditLog) {
	a.mu.Lock()
	defer a.mu.Unlock()
	a.logs = append(a.logs, entry)
	log.Printf("AUDIT: user=%d source_tenant=%d target_tenant=%d action=%s resource=%s success=%t",
		entry.UserID, entry.SourceTenantID, entry.TargetTenantID,
		entry.Action, entry.Resource, entry.Success)
}

// TenantAccessControl provides fine-grained cross-tenant authorization
type TenantAccessControl struct {
	db *sql.DB
}

// CheckAccess validates tenant access with explicit permission checks
func (tac *TenantAccessControl) CheckAccess(ctx context.Context, user *User, targetTenantID int, action string, resource string) (bool, string) {
	// LAYER 1: Same tenant - always allowed for basic operations
	if user.TenantID == targetTenantID {
		return true, "same_tenant"
	}

	// LAYER 2: Super admin with explicit cross-tenant rights
	if user.Role == RoleSuperAdmin {
		// Even super admins need explicit permissions
		hasPermission, err := tac.checkExplicitPermission(ctx, user.ID, targetTenantID, action, resource)
		if err != nil {
			log.Printf("ERROR: Permission check failed for user %d: %v", user.ID, err)
			return false, "permission_check_error"
		}
		if !hasPermission {
			return false, "super_admin_no_explicit_permission"
		}
		return true, "super_admin_explicit_grant"
	}

	// LAYER 3: Check tenant sharing agreements
	isShared, err := tac.checkTenantSharing(ctx, user.TenantID, targetTenantID, resource)
	if err != nil {
		return false, "sharing_check_error"
	}
	if isShared {
		return true, "tenant_sharing_agreement"
	}

	// LAYER 4: Check time-limited delegated access
	hasDelegation, err := tac.checkDelegatedAccess(ctx, user.ID, targetTenantID, action)
	if err != nil {
		return false, "delegation_check_error"
	}
	if hasDelegation {
		return true, "delegated_access"
	}

	return false, "no_cross_tenant_permission"
}

func (tac *TenantAccessControl) checkExplicitPermission(ctx context.Context, userID int, targetTenantID int, action string, resource string) (bool, error) {
	query := `
		SELECT COUNT(*) FROM cross_tenant_permissions 
		WHERE user_id = $1 
		AND target_tenant_id = $2 
		AND (action = $3 OR action = '*')
		AND (resource = $4 OR resource = '*')
		AND expires_at > NOW()
		AND revoked_at IS NULL`

	var count int
	err := tac.db.QueryRowContext(ctx, query, userID, targetTenantID, action, resource).Scan(&count)
	return count > 0, err
}

func (tac *TenantAccessControl) checkTenantSharing(ctx context.Context, sourceTenantID int, targetTenantID int, resource string) (bool, error) {
	query := `
		SELECT COUNT(*) FROM tenant_sharing_agreements
		WHERE source_tenant_id = $1
		AND target_tenant_id = $2
		AND resource_type = $3
		AND status = 'active'
		AND (expires_at IS NULL OR expires_at > NOW())`

	var count int
	err := tac.db.QueryRowContext(ctx, query, sourceTenantID, targetTenantID, resource).Scan(&count)
	return count > 0, err
}

func (tac *TenantAccessControl) checkDelegatedAccess(ctx context.Context, userID int, targetTenantID int, action string) (bool, error) {
	query := `
		SELECT COUNT(*) FROM delegated_access_tokens
		WHERE user_id = $1
		AND tenant_id = $2
		AND action = $3
		AND expires_at > NOW()
		AND used_at IS NULL`

	var count int
	err := tac.db.QueryRowContext(ctx, query, userID, targetTenantID, action).Scan(&count)
	return count > 0, err
}

// EnhancedTenantMiddleware with cross-tenant support
func EnhancedTenantMiddleware(tac *TenantAccessControl) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			user, err := getUserFromJWT(r)
			if err != nil {
				logSecurityEvent(r, "invalid_authentication", nil, 0)
				http.Error(w, "Unauthorized", http.StatusUnauthorized)
				return
			}

			// Determine target tenant from URL if present
			vars := mux.Vars(r)
			targetTenantID := user.TenantID // Default to user's tenant

			if tenantStr, exists := vars["tenant_id"]; exists {
				parsedID, err := strconv.Atoi(tenantStr)
				if err != nil {
					http.Error(w, "Invalid tenant ID", http.StatusBadRequest)
					return
				}
				targetTenantID = parsedID
			}

			// Check cross-tenant access if needed
			if targetTenantID != user.TenantID {
				resource := extractResourceType(r.URL.Path)
				action := mapHTTPMethodToAction(r.Method)

				allowed, reason := tac.CheckAccess(r.Context(), user, targetTenantID, action, resource)

				// ALWAYS audit cross-tenant access attempts
				auditLogger.Log(AuditLog{
					Timestamp:      time.Now(),
					UserID:         user.ID,
					SourceTenantID: user.TenantID,
					TargetTenantID: targetTenantID,
					Action:         action,
					Resource:       resource,
					IPAddress:      r.RemoteAddr,
					UserAgent:      r.UserAgent(),
					Success:        allowed,
					Reason:         reason,
				})

				if !allowed {
					// Return 404 to prevent tenant enumeration
					http.Error(w, "Not found", http.StatusNotFound)
					return
				}
			}

			// Store verified tenant in context
			ctx := context.WithValue(r.Context(), tenantContextKey, targetTenantID)
			ctx = context.WithValue(ctx, userContextKey, user)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// TenantScopedQuery enforces tenant isolation at database level
type TenantScopedQuery struct {
	db       *sql.DB
	tenantID int
}

func NewTenantScopedQuery(ctx context.Context, db *sql.DB) (*TenantScopedQuery, error) {
	tenantID, ok := ctx.Value(tenantContextKey).(int)
	if !ok {
		return nil, fmt.Errorf("no tenant context")
	}
	return &TenantScopedQuery{db: db, tenantID: tenantID}, nil
}

// Query automatically injects tenant_id into all queries
func (tsq *TenantScopedQuery) Query(ctx context.Context, query string, args ...interface{}) (*sql.Rows, error) {
	// Prepend tenant_id to args
	finalArgs := append([]interface{}{tsq.tenantID}, args...)
	return tsq.db.QueryContext(ctx, query, finalArgs...)
}

// SecureGetInvoice with full multi-tenant protection
func SecureGetInvoice(tac *TenantAccessControl) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		tsq, err := NewTenantScopedQuery(r.Context(), db)
		if err != nil {
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		vars := mux.Vars(r)
		invoiceID := vars["invoice_id"]

		// $1 is always tenant_id from TenantScopedQuery
		query := `SELECT id, tenant_id, amount, customer 
		          FROM invoices 
		          WHERE tenant_id = $1 AND id = $2`

		rows, err := tsq.Query(r.Context(), query, invoiceID)
		if err != nil {
			log.Printf("Query error: %v", err)
			http.Error(w, "Internal error", http.StatusInternalServerError)
			return
		}
		defer rows.Close()

		if !rows.Next() {
			http.Error(w, "Not found", http.StatusNotFound)
			return
		}

		var invoice struct {
			ID       int     `json:"id"`
			TenantID int     `json:"tenant_id"`
			Amount   float64 `json:"amount"`
			Customer string  `json:"customer"`
		}
		err = rows.Scan(&invoice.ID, &invoice.TenantID, &invoice.Amount, &invoice.Customer)
		if err != nil {
			log.Printf("Scan error: %v", err)
			http.Error(w, "Internal error", http.StatusInternalServerError)
			return
		}

		json.NewEncoder(w).Encode(invoice)
	}
}

func getUserFromJWT(r *http.Request) (*User, error) {
	// Production: validate JWT signature and extract claims
	return &User{ID: 1, TenantID: 1, Role: RoleTenantUser}, nil
}

func logSecurityEvent(r *http.Request, event string, user *User, tenantID int) {
	log.Printf("SECURITY: event=%s ip=%s tenant=%d", event, r.RemoteAddr, tenantID)
}

func extractResourceType(path string) string {
	// Extract resource type from URL path
	return "invoice"
}

func mapHTTPMethodToAction(method string) string {
	switch method {
	case "GET":
		return "read"
	case "POST":
		return "create"
	case "PUT", "PATCH":
		return "update"
	case "DELETE":
		return "delete"
	default:
		return "unknown"
	}
}

func main() {
	tac := &TenantAccessControl{db: db}
	r := mux.NewRouter()

	// Apply tenant middleware to all routes
	r.Use(EnhancedTenantMiddleware(tac))

	r.HandleFunc("/api/invoices/{invoice_id}", SecureGetInvoice(tac)).Methods("GET")

	http.ListenAndServe(":8080", r)
}
```

**Defense in Depth Layers**:

1. **JWT-Based Tenant Identity**: Tenant ID extracted from cryptographically signed JWT, never from user input
```go
user, err := getUserFromJWT(r) // Verified claim, not URL parameter
```

2. **Explicit Cross-Tenant Permissions**: Even admins require database-stored permissions with expiration
```go
// Time-limited, auditable permissions
WHERE expires_at > NOW() AND revoked_at IS NULL
```

3. **Query-Level Isolation**: TenantScopedQuery wrapper ensures tenant filter is always applied
```go
finalArgs := append([]interface{}{tsq.tenantID}, args...)
```

**Additional Protections**:
- **Comprehensive audit logging**: All cross-tenant access attempts logged with source/target tenant, user, action, and result
- **Tenant enumeration prevention**: Return 404 instead of 403 to prevent attackers from discovering valid tenant IDs
- **Row-Level Security (RLS)**: In PostgreSQL, add RLS policies as additional database-level enforcement
- **Rate limiting per tenant**: Prevent one tenant from impacting others through excessive API usage
- **Anomaly detection**: Monitor for unusual cross-tenant access patterns and alert security team

Multi-tenant data isolation is critical - the 2023 Citrix ShareFile vulnerability (CVE-2023-24489) allowed attackers to access files from other tenants due to improper authorization checks, affecting hundreds of thousands of enterprise accounts.

**VULNERABLE CODE**:

```php
<?php
// WARNING: This code has critical multi-tenant isolation flaws

class DocumentController
{
    private $pdo;

    public function __construct($pdo)
    {
        $this->pdo = $pdo;
    }

    // VULNERABLE: No tenant isolation check
    public function getDocument($documentId)
    {
        // User can access ANY document by changing the ID
        $stmt = $this->pdo->prepare(
            "SELECT * FROM documents WHERE id = ?"
        );
        $stmt->execute([$documentId]);
        return $stmt->fetch(PDO::FETCH_ASSOC);
    }

    // VULNERABLE: Tenant ID from user input can be manipulated
    public function listDocuments($tenantId)
    {
        $stmt = $this->pdo->prepare(
            "SELECT * FROM documents WHERE tenant_id = ?"
        );
        $stmt->execute([$tenantId]);
        return $stmt->fetchAll(PDO::FETCH_ASSOC);
    }

    // VULNERABLE: Allows cross-tenant file sharing without validation
    public function shareDocument($documentId, $targetTenantId)
    {
        $stmt = $this->pdo->prepare(
            "INSERT INTO shared_documents (document_id, shared_with_tenant) VALUES (?, ?)"
        );
        return $stmt->execute([$documentId, $targetTenantId]);
    }
}

// Usage - attacker can manipulate parameters
$doc = $controller->getDocument($_GET['doc_id']);
$docs = $controller->listDocuments($_GET['tenant_id']);
```

**Attack Payload**:
```text
# Enumerate other tenant's documents by changing document ID
GET /api/documents?doc_id=1001
GET /api/documents?doc_id=1002
GET /api/documents?doc_id=1003

# Access another tenant's file list by changing tenant_id
GET /api/documents/list?tenant_id=competitor_corp

# IDOR attack - sequential ID enumeration
for id in {1..10000}; do curl "https://app.com/api/documents?doc_id=$id"; done
```

**Why This Is Dangerous**:
- No verification that the requesting user belongs to the document's tenant
- Tenant ID accepted from user input instead of server-side session
- Sequential/predictable document IDs enable enumeration attacks
- No audit trail for cross-tenant access attempts
- Shared documents bypass tenant boundaries entirely

**SECURE VERSION**:

```php
<?php

class SecureDocumentController
{
    private $pdo;
    private $logger;

    public function __construct(PDO $pdo, Logger $logger)
    {
        $this->pdo = $pdo;
        $this->logger = $logger;
    }

    /**
     * Get tenant ID from authenticated session - NEVER from user input
     */
    private function getCurrentTenantId(): string
    {
        if (!isset($_SESSION['authenticated']) || !$_SESSION['authenticated']) {
            throw new UnauthorizedException('Not authenticated');
        }
        return $_SESSION['tenant_id'];
    }

    /**
     * SECURE: Always filter by tenant from session
     */
    public function getDocument(string $documentId): ?array
    {
        $tenantId = $this->getCurrentTenantId();

        // CRITICAL: Always include tenant_id in WHERE clause
        $stmt = $this->pdo->prepare(
            "SELECT d.* FROM documents d 
             WHERE d.id = ? AND d.tenant_id = ?
             UNION
             SELECT d.* FROM documents d
             INNER JOIN shared_documents sd ON d.id = sd.document_id
             WHERE d.id = ? AND sd.shared_with_tenant = ?"
        );
        $stmt->execute([$documentId, $tenantId, $documentId, $tenantId]);
        $document = $stmt->fetch(PDO::FETCH_ASSOC);

        // Log access attempt for audit
        $this->logger->info('Document access', [
            'document_id' => $documentId,
            'tenant_id' => $tenantId,
            'user_id' => $_SESSION['user_id'],
            'success' => $document !== false,
            'ip' => $_SERVER['REMOTE_ADDR']
        ]);

        if (!$document) {
            throw new ForbiddenException('Document not found or access denied');
        }

        return $document;
    }

    /**
     * SECURE: List only current tenant's documents
     */
    public function listDocuments(): array
    {
        $tenantId = $this->getCurrentTenantId();

        $stmt = $this->pdo->prepare(
            "SELECT * FROM documents WHERE tenant_id = ?"
        );
        $stmt->execute([$tenantId]);
        return $stmt->fetchAll(PDO::FETCH_ASSOC);
    }
}
```

**Key Security Controls**:
- **Tenant ID from session only**: Never accept tenant_id from user input; always derive from authenticated session
- **Compound query filters**: Every query includes tenant_id filter alongside resource ID
- **Audit logging**: All access attempts logged with tenant context for security monitoring
- **Fail-closed design**: Missing or invalid tenant context throws exception rather than defaulting

Hierarchical tenants and cross-tenant admin access are where most multi-tenant vulnerabilities occur. The 2024 Salesforce Communities data exposure incidents showed how misconfigured guest access and admin permissions led to unauthorized data access across organizations.

**PRODUCTION PATTERN**:

```php
<?php

declare(strict_types=1);

namespace App\Security;

use PDO;
use Psr\Log\LoggerInterface;

class TenantSecurityContext
{
    private PDO $pdo;
    private LoggerInterface $logger;
    private LoggerInterface $auditLogger;
    private array $tenantHierarchyCache = [];

    public function __construct(
        PDO $pdo,
        LoggerInterface $logger,
        LoggerInterface $auditLogger
    ) {
        $this->pdo = $pdo;
        $this->logger = $logger;
        $this->auditLogger = $auditLogger;
    }

    /**
     * Get all tenant IDs the current user can access
     * Includes: own tenant, child tenants (if parent), cross-tenant access grants
     */
    public function getAccessibleTenantIds(): array
    {
        $currentTenantId = $this->getCurrentTenantId();
        $userId = $this->getCurrentUserId();
        $accessibleTenants = [$currentTenantId];

        // Check for hierarchical access (parent can see children)
        if ($this->hasRole('TENANT_ADMIN')) {
            $childTenants = $this->getChildTenants($currentTenantId);
            $accessibleTenants = array_merge($accessibleTenants, $childTenants);
        }

        // Check for explicit cross-tenant grants (support staff)
        if ($this->hasRole('SUPPORT_ADMIN')) {
            $grantedTenants = $this->getExplicitTenantGrants($userId);
            $accessibleTenants = array_merge($accessibleTenants, $grantedTenants);
        }

        return array_unique($accessibleTenants);
    }

    /**
     * Verify access to a specific resource with full audit trail
     */
    public function verifyResourceAccess(
        string $resourceType,
        string $resourceId,
        string $action = 'read'
    ): bool {
        $startTime = microtime(true);
        $accessGranted = false;
        $denyReason = 'Unknown';

        try {
            // Step 1: Get resource's tenant
            $resourceTenant = $this->getResourceTenant($resourceType, $resourceId);

            if ($resourceTenant === null) {
                $denyReason = 'Resource not found';
                return false;
            }

            // Step 2: Check if user's accessible tenants include resource tenant
            $accessibleTenants = $this->getAccessibleTenantIds();

            if (!in_array($resourceTenant, $accessibleTenants, true)) {
                $denyReason = 'Tenant mismatch';
                $this->logSecurityEvent('CROSS_TENANT_ACCESS_ATTEMPT', [
                    'resource_type' => $resourceType,
                    'resource_id' => $resourceId,
                    'resource_tenant' => $resourceTenant,
                    'user_tenant' => $this->getCurrentTenantId(),
                    'severity' => 'HIGH'
                ]);
                return false;
            }

            // Step 3: Check action-specific permissions
            $accessGranted = $this->checkActionPermission(
                $resourceType,
                $resourceId,
                $action,
                $resourceTenant
            );

            if (!$accessGranted) {
                $denyReason = 'Insufficient permissions for action';
            }

            return $accessGranted;

        } finally {
            // Always log access decision for audit
            $this->auditLogger->info('Resource access check', [
                'resource_type' => $resourceType,
                'resource_id' => $resourceId,
                'action' => $action,
                'user_id' => $this->getCurrentUserId(),
                'tenant_id' => $this->getCurrentTenantId(),
                'access_granted' => $accessGranted,
                'deny_reason' => $accessGranted ? null : $denyReason,
                'duration_ms' => (microtime(true) - $startTime) * 1000,
                'ip_address' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
                'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown',
                'timestamp' => date('c')
            ]);
        }
    }

    /**
     * Get child tenants with cycle detection
     */
    private function getChildTenants(string $parentTenantId, int $maxDepth = 5): array
    {
        if (isset($this->tenantHierarchyCache[$parentTenantId])) {
            return $this->tenantHierarchyCache[$parentTenantId];
        }

        $children = [];
        $toProcess = [$parentTenantId];
        $processed = [];
        $depth = 0;

        while (!empty($toProcess) && $depth < $maxDepth) {
            $currentId = array_shift($toProcess);

            // Prevent infinite loops from circular references
            if (in_array($currentId, $processed, true)) {
                $this->logger->warning('Circular tenant hierarchy detected', [
                    'parent' => $parentTenantId,
                    'circular_at' => $currentId
                ]);
                continue;
            }
            $processed[] = $currentId;

            $stmt = $this->pdo->prepare(
                "SELECT id FROM tenants WHERE parent_tenant_id = ? AND status = 'active'"
            );
            $stmt->execute([$currentId]);
            $childIds = $stmt->fetchAll(PDO::FETCH_COLUMN);

            foreach ($childIds as $childId) {
                $children[] = $childId;
                $toProcess[] = $childId;
            }
            $depth++;
        }

        $this->tenantHierarchyCache[$parentTenantId] = $children;
        return $children;
    }

    /**
     * Time-limited cross-tenant access grants for support
     */
    private function getExplicitTenantGrants(string $userId): array
    {
        $stmt = $this->pdo->prepare(
            "SELECT target_tenant_id FROM cross_tenant_grants 
             WHERE user_id = ? 
             AND expires_at > NOW() 
             AND revoked_at IS NULL
             AND approved_by IS NOT NULL"
        );
        $stmt->execute([$userId]);
        return $stmt->fetchAll(PDO::FETCH_COLUMN);
    }

    /**
     * Grant temporary cross-tenant access with approval workflow
     */
    public function grantCrossTenantAccess(
        string $targetUserId,
        string $targetTenantId,
        string $reason,
        int $durationHours = 4
    ): string {
        // Verify granter has permission
        if (!$this->hasRole('SECURITY_ADMIN')) {
            throw new ForbiddenException('Only Security Admins can grant cross-tenant access');
        }

        // Maximum duration limit
        $maxHours = 24;
        $durationHours = min($durationHours, $maxHours);

        $grantId = bin2hex(random_bytes(16));
        $expiresAt = date('Y-m-d H:i:s', strtotime("+{$durationHours} hours"));

        $stmt = $this->pdo->prepare(
            "INSERT INTO cross_tenant_grants 
             (id, user_id, target_tenant_id, granted_by, approved_by, reason, expires_at, created_at)
             VALUES (?, ?, ?, ?, ?, ?, ?, NOW())"
        );
        $stmt->execute([
            $grantId,
            $targetUserId,
            $targetTenantId,
            $this->getCurrentUserId(),
            $this->getCurrentUserId(), // Self-approval for security admins
            $reason,
            $expiresAt
        ]);

        // Critical security event - always log
        $this->logSecurityEvent('CROSS_TENANT_ACCESS_GRANTED', [
            'grant_id' => $grantId,
            'target_user' => $targetUserId,
            'target_tenant' => $targetTenantId,
            'granted_by' => $this->getCurrentUserId(),
            'reason' => $reason,
            'expires_at' => $expiresAt,
            'severity' => 'HIGH'
        ]);

        // Notify tenant admin and security team
        $this->notifySecurityTeam('Cross-tenant access granted', [
            'grant_id' => $grantId,
            'target_tenant' => $targetTenantId
        ]);

        return $grantId;
    }

    private function logSecurityEvent(string $eventType, array $context): void
    {
        $this->auditLogger->warning($eventType, array_merge($context, [
            'event_type' => $eventType,
            'timestamp' => date('c'),
            'ip_address' => $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ]));
    }

    private function getCurrentTenantId(): string
    {
        if (empty($_SESSION['tenant_id'])) {
            throw new UnauthorizedException('No tenant context');
        }
        return $_SESSION['tenant_id'];
    }

    private function getCurrentUserId(): string
    {
        if (empty($_SESSION['user_id'])) {
            throw new UnauthorizedException('Not authenticated');
        }
        return $_SESSION['user_id'];
    }

    private function hasRole(string $role): bool
    {
        return in_array($role, $_SESSION['roles'] ?? [], true);
    }
}
