namespace SecureApp.MultiTenancy
{
    // Tenant-aware base entity
    public interface ITenantEntity
    {
        string TenantId { get; set; }
    }

    // Tenant context service
    public interface ITenantContext
    {
        string TenantId { get; }
        bool IsSuperAdmin { get; }
