    public class TenantContext : ITenantContext
    {
        private readonly IHttpContextAccessor _httpContextAccessor;
        private readonly ILogger<TenantContext> _logger;

        public TenantContext(
            IHttpContextAccessor httpContextAccessor,
            ILogger<TenantContext> logger)
        {
            _httpContextAccessor = httpContextAccessor;
            _logger = logger;
        }

        public string TenantId
        {
            get
            {
                var user = _httpContextAccessor.HttpContext?.User;
                var tenantClaim = user?.FindFirst("tenant_id");

                if (tenantClaim == null || string.IsNullOrEmpty(tenantClaim.Value))
                {
                    throw new UnauthorizedAccessException("No tenant context available");
                }

                return tenantClaim.Value;
            }
        }

        public bool IsSuperAdmin =>
            _httpContextAccessor.HttpContext?.User?
                .HasClaim("role", "platform_admin") ?? false;

        public string[] AllowedTenants
        {
            get
            {
                var tenantsClaimValue = _httpContextAccessor.HttpContext?.User?
                    .FindFirst("allowed_tenants")?.Value;

                return string.IsNullOrEmpty(tenantsClaimValue)
                    ? new[] { TenantId }
                    : tenantsClaimValue.Split(',');
            }
        }
    }

    // Multi-tenant DbContext with automatic filtering
    public class MultiTenantDbContext : DbContext
    {
        private readonly ITenantContext _tenantContext;
        private readonly ILogger<MultiTenantDbContext> _logger;

        public MultiTenantDbContext(
            DbContextOptions<MultiTenantDbContext> options,
            ITenantContext tenantContext,
            ILogger<MultiTenantDbContext> logger)
            : base(options)
        {
            _tenantContext = tenantContext;
            _logger = logger;
        }

        public DbSet<Invoice> Invoices { get; set; }
        public DbSet<Customer> Customers { get; set; }
        public DbSet<TenantAuditLog> AuditLogs { get; set; }

        protected override void OnModelCreating(ModelBuilder modelBuilder)
        {
            base.OnModelCreating(modelBuilder);

            // DEFENSE IN DEPTH: Global query filter for ALL tenant entities
            foreach (var entityType in modelBuilder.Model.GetEntityTypes())
            {
                if (typeof(ITenantEntity).IsAssignableFrom(entityType.ClrType))
                {
                    var parameter = Expression.Parameter(entityType.ClrType, "e");
                    var tenantProperty = Expression.Property(parameter, nameof(ITenantEntity.TenantId));

                    // Filter includes allowed tenants for admins
                    var filter = Expression.Lambda(
                        Expression.Call(
                            typeof(Enumerable),
                            nameof(Enumerable.Contains),
                            new[] { typeof(string) },
                            Expression.Constant(_tenantContext.AllowedTenants),
                            tenantProperty),
                        parameter);

                    modelBuilder.Entity(entityType.ClrType).HasQueryFilter(filter);
                }
            }

            // Row-Level Security policy via stored procedure
            modelBuilder.HasDbFunction(typeof(MultiTenantDbContext)
                .GetMethod(nameof(TenantSecurityPolicy))!);
        }

        // Database-level RLS function
        [DbFunction("fn_tenant_security_policy", "security")]
        public static bool TenantSecurityPolicy(string rowTenantId, string userTenantId)
            => throw new NotSupportedException();

        // Override SaveChanges to enforce tenant on new entities
        public override async Task<int> SaveChangesAsync(
            CancellationToken cancellationToken = default)
        {
            foreach (var entry in ChangeTracker.Entries<ITenantEntity>())
            {
                switch (entry.State)
                {
                    case EntityState.Added:
                        // Auto-assign tenant on creation
                        entry.Entity.TenantId = _tenantContext.TenantId;
                        break;

                    case EntityState.Modified:
                        // Prevent tenant modification
                        if (entry.Property(nameof(ITenantEntity.TenantId)).IsModified)
                        {
                            _logger.LogCritical(
                                "SECURITY ALERT: Attempted tenant ID modification on {Entity}",
                                entry.Entity.GetType().Name);
                            throw new SecurityException("Tenant ID cannot be modified");
                        }
                        break;
                }
            }

            return await base.SaveChangesAsync(cancellationToken);
        }
    }

    // Cross-tenant operation authorization
    [AttributeUsage(AttributeTargets.Method)]
    public class RequiresCrossTenantAuthorizationAttribute : ActionFilterAttribute
    {
        public override async Task OnActionExecutionAsync(
            ActionExecutingContext context,
            ActionExecutionDelegate next)
        {
            var tenantContext = context.HttpContext.RequestServices
                .GetRequiredService<ITenantContext>();
            var logger = context.HttpContext.RequestServices
                .GetRequiredService<ILogger<RequiresCrossTenantAuthorizationAttribute>>();
            var auditService = context.HttpContext.RequestServices
                .GetRequiredService<IAuditService>();

            // Check if target tenant is in request
            if (context.ActionArguments.TryGetValue("targetTenantId", out var targetTenant))
            {
                var targetTenantId = targetTenant?.ToString();

                if (!tenantContext.AllowedTenants.Contains(targetTenantId))
                {
                    logger.LogCritical(
                        "SECURITY ALERT: User attempted cross-tenant access to {TargetTenant} " +
                        "from {SourceTenant}. Allowed tenants: {AllowedTenants}",
                        targetTenantId,
                        tenantContext.TenantId,
                        string.Join(",", tenantContext.AllowedTenants));

                    await auditService.LogSecurityEventAsync(
                        "CROSS_TENANT_ACCESS_DENIED",
                        context.HttpContext.User.FindFirstValue(ClaimTypes.NameIdentifier),
                        tenantContext.TenantId,
                        targetTenantId);

                    context.Result = new ForbidResult();
                    return;
                }

                // Audit successful cross-tenant access
                await auditService.LogSecurityEventAsync(
                    "CROSS_TENANT_ACCESS_GRANTED",
                    context.HttpContext.User.FindFirstValue(ClaimTypes.NameIdentifier),
                    tenantContext.TenantId,
                    targetTenantId);
            }

            await next();
        }
    }

