            return jsonify({'error': 'Unauthorized'}), 401
        try:
            g.user_id = decode_token(token)
            g.tenant_id = get_user_tenant(g.user_id)
            if not g.tenant_id:
                return jsonify({'error': 'Invalid tenant'}), 403
        except Exception:
            return jsonify({'error': 'Invalid token'}), 401
        return f(*args, **kwargs)
    return decorated

def tenant_scoped_query(query: str, params: tuple) -> tuple:
    """Ensure all queries include tenant_id filter from session."""
    # SECURITY: Always inject tenant_id from authenticated session
    return query, params + (g.tenant_id,)

@app.route('/api/employees/<employee_uuid>')
@require_auth
def get_employee(employee_uuid: str):
    # SECURE: Use UUID instead of sequential ID
    try:
        uuid.UUID(employee_uuid)  # Validate UUID format
    except ValueError:
        return jsonify({'error': 'Invalid employee ID format'}), 400

    db = get_db()
    # SECURE: Always filter by tenant_id from session
    cursor = db.execute(
        'SELECT id, uuid, name, email, department FROM employees WHERE uuid = ? AND tenant_id = ?',
        (employee_uuid, g.tenant_id)
    )
    employee = cursor.fetchone()

    if employee:
        app.logger.info(f"Employee {employee_uuid} accessed by user {g.user_id} in tenant {g.tenant_id}")
        return jsonify(dict(employee))

    # SECURE: Same error for not found and unauthorized (prevent enumeration)
    app.logger.warning(f"Unauthorized or missing employee access: {employee_uuid} by user {g.user_id}")
    return jsonify({'error': 'Employee not found'}), 404

@app.route('/api/employees')
@require_auth
def list_employees():
    db = get_db()
    # SECURE: tenant_id ONLY from authenticated session, never from request
    cursor = db.execute(
        'SELECT uuid, name, email, department FROM employees WHERE tenant_id = ?',
        (g.tenant_id,)
    )
    app.logger.info(f"Employee list accessed by user {g.user_id} in tenant {g.tenant_id}")
    return jsonify([dict(row) for row in cursor.fetchall()])
```

**Key Security Controls**:
- **Mandatory tenant filtering**: Every query includes `AND tenant_id = ?` with value from authenticated session, never from user input
- **UUID identifiers**: Prevents sequential ID enumeration attacks (IDOR)
- **Uniform error responses**: Returns same error for "not found" and "unauthorized" to prevent data existence enumeration
- **Audit logging**: All data access is logged with user, tenant, and resource identifiers

