class TenantAwarePool {
  constructor(basePool) {
    this.basePool = basePool;
  }

  async getConnection(tenantId) {
    const client = await this.basePool.connect();

    // Set tenant context at database level using RLS
    await client.query('SET app.current_tenant = $1', [tenantId]);

    return {
      query: async (sql, params) => {
        // Audit all queries
        securityLogger.info('Query executed', {
          tenant_id: tenantId,
          query_hash: Buffer.from(sql).toString('base64').substring(0, 32),
          timestamp: new Date().toISOString()
        });
        return client.query(sql, params);
      },
      release: () => client.release()
    };
  }
}

const basePool = new Pool({ connectionString: process.env.DATABASE_URL });
const tenantPool = new TenantAwarePool(basePool);

// LAYER 2: Tenant context middleware with strict validation
const tenantContextMiddleware = async (req, res, next) => {
  try {
    const token = req.headers.authorization?.replace('Bearer ', '');
    if (!token) {
      securityLogger.warn('Missing authentication', { ip: req.ip });
      return res.status(401).json({ error: 'Authentication required' });
    }

    const decoded = jwt.verify(token, process.env.JWT_SECRET, {
      algorithms: ['RS256'],
      issuer: process.env.JWT_ISSUER
    });

    // Validate tenant exists and is active
    const tenantCheck = await basePool.query(
      'SELECT id, status FROM tenants WHERE id = $1',
      [decoded.tenant_id]
    );

    if (tenantCheck.rows.length === 0 || tenantCheck.rows[0].status !== 'active') {
      securityLogger.error('Invalid tenant access attempt', {
        claimed_tenant: decoded.tenant_id,
        user_id: decoded.user_id,
        ip: req.ip
      });
      return res.status(403).json({ error: 'Access denied' });
    }

    req.tenantId = decoded.tenant_id;
    req.userId = decoded.user_id;
    req.userRole = decoded.role;

    // Get tenant-scoped database connection
    req.db = await tenantPool.getConnection(req.tenantId);

    // Ensure connection is released after request
    res.on('finish', () => req.db.release());

    next();
  } catch (error) {
    securityLogger.error('Authentication failure', { error: error.message, ip: req.ip });
    return res.status(401).json({ error: 'Invalid authentication' });
  }
};

