```java
import java.sql.*;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureInvoiceController extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureInvoiceController.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/saas_db";
    private static final String DB_USER = "app_user";
    private static final String DB_PASS = "app_password";

    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws ServletException, IOException {

        // SECURE: Get tenant from authenticated session, never from request
        HttpSession session = request.getSession(false);
        if (session == null) {
            response.sendError(401, "Authentication required");
            return;
        }

        // Tenant ID is bound to authenticated session - cannot be manipulated
        String tenantId = (String) session.getAttribute("tenant_id");
        String userId = (String) session.getAttribute("user_id");

        if (tenantId == null || userId == null) {
            logger.warn("Missing tenant context for session: {}", session.getId());
            response.sendError(403, "Invalid session context");
            return;
        }

        String invoiceId = request.getParameter("invoice_id");
        if (invoiceId == null || !invoiceId.matches("^[0-9]+$")) {
            response.sendError(400, "Invalid invoice ID");
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // SECURE: Tenant ID from session, not request
            String sql = "SELECT * FROM invoices WHERE tenant_id = ? AND id = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, tenantId);  // From session - immutable
            stmt.setString(2, invoiceId);

            ResultSet rs = stmt.executeQuery();
            if (rs.next()) {
                logger.info("Invoice {} accessed by user {} in tenant {}", 
                    invoiceId, userId, tenantId);
                writeJsonResponse(response, rs);
            } else {
                response.sendError(404, "Invoice not found");
            }
        } catch (SQLException e) {
            logger.error("Database error for tenant {}: {}", tenantId, e.getMessage());
            response.sendError(500, "Internal server error");
        }
    }
}
```

**Key Security Controls**:
- **Session-bound tenant context**: Tenant ID is extracted from authenticated session, not from request parameters
- **Immutable tenant binding**: Once authenticated, user's tenant cannot be changed without re-authentication
- **Input validation**: Invoice ID validated before use
- **Audit logging**: All data access logged with tenant and user context

Hierarchical tenants and cross-tenant access are common enterprise requirements that dramatically increase the attack surface. You need a comprehensive tenant isolation layer with explicit permission grants.

**PRODUCTION PATTERN**:

```java
import java.sql.*;
import java.util.*;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class TenantIsolationService {
    private static final Logger logger = LoggerFactory.getLogger(TenantIsolationService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    private final DataSource dataSource;
    private final TenantHierarchyCache hierarchyCache;

    public TenantIsolationService(DataSource dataSource, TenantHierarchyCache cache) {
        this.dataSource = dataSource;
        this.hierarchyCache = cache;
    }

    /**
     * Core tenant access check - validates if user can access target tenant's data
     */
    public TenantAccessResult checkTenantAccess(SecurityContext ctx, String targetTenantId) {
        String userTenantId = ctx.getTenantId();
        String userId = ctx.getUserId();
        Set<String> userRoles = ctx.getRoles();

        // Case 1: Same tenant - always allowed
        if (userTenantId.equals(targetTenantId)) {
            return TenantAccessResult.allowed("SAME_TENANT");
        }

        // Case 2: Hierarchical access - parent can access child tenants
        if (hierarchyCache.isAncestorOf(userTenantId, targetTenantId)) {
            if (userRoles.contains("TENANT_ADMIN") || userRoles.contains("PARENT_ORG_VIEWER")) {
                auditLogger.info("HIERARCHY_ACCESS|user={}|from={}|to={}|roles={}",
                    userId, userTenantId, targetTenantId, userRoles);
                return TenantAccessResult.allowed("PARENT_HIERARCHY");
            }
        }

        // Case 3: Explicit cross-tenant grant (support agents, auditors)
        Optional<CrossTenantGrant> grant = getCrossTenantGrant(userId, targetTenantId);
        if (grant.isPresent()) {
            CrossTenantGrant g = grant.get();

            // Validate grant is still active and not expired
            if (g.isExpired()) {
                auditLogger.warn("EXPIRED_GRANT|user={}|target={}|grant_id={}",
                    userId, targetTenantId, g.getId());
                return TenantAccessResult.denied("GRANT_EXPIRED");
            }

            // Validate grant scope
            if (!g.getScopes().contains(ctx.getRequestedScope())) {
                auditLogger.warn("SCOPE_VIOLATION|user={}|target={}|requested={}|allowed={}",
                    userId, targetTenantId, ctx.getRequestedScope(), g.getScopes());
                return TenantAccessResult.denied("SCOPE_NOT_GRANTED");
            }

            auditLogger.info("CROSS_TENANT_ACCESS|user={}|from={}|to={}|grant_id={}|scope={}",
                userId, userTenantId, targetTenantId, g.getId(), ctx.getRequestedScope());
            return TenantAccessResult.allowed("EXPLICIT_GRANT", g.getScopes());
        }

        // Default deny - log attempted violation
        auditLogger.warn("TENANT_ISOLATION_BLOCKED|user={}|from={}|to={}|ip={}",
            userId, userTenantId, targetTenantId, ctx.getClientIp());
        return TenantAccessResult.denied("NO_ACCESS");
    }

    private Optional<CrossTenantGrant> getCrossTenantGrant(String userId, String targetTenantId) {
        String sql = "SELECT id, user_id, target_tenant_id, scopes, expires_at, created_by " +
                     "FROM cross_tenant_grants " +
                     "WHERE user_id = ? AND target_tenant_id = ? AND revoked = false";

        try (Connection conn = dataSource.getConnection();
             PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, userId);
            stmt.setString(2, targetTenantId);

            ResultSet rs = stmt.executeQuery();
            if (rs.next()) {
                return Optional.of(CrossTenantGrant.fromResultSet(rs));
            }
        } catch (SQLException e) {
            logger.error("Failed to check cross-tenant grant: {}", e.getMessage());
        }
        return Optional.empty();
    }
}

/**
 * Hibernate filter for automatic tenant isolation at the ORM layer
 */
public class TenantAwareRepository<T> {
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    @PersistenceContext
    private EntityManager entityManager;

    @Autowired
    private TenantContext tenantContext;

    @Autowired
    private TenantIsolationService isolationService;

    public Optional<T> findById(Class<T> entityClass, Long id, String targetTenantId) {
        SecurityContext ctx = SecurityContextHolder.getContext();

        // Always validate tenant access before any query
        TenantAccessResult accessResult = isolationService.checkTenantAccess(ctx, targetTenantId);

        if (!accessResult.isAllowed()) {
            throw new TenantAccessDeniedException(
                String.format("Access denied to tenant %s: %s", targetTenantId, accessResult.getReason()));
        }

        // Enable Hibernate tenant filter
        Session session = entityManager.unwrap(Session.class);
        session.enableFilter("tenantFilter")
               .setParameter("tenantId", targetTenantId);

        try {
            T entity = entityManager.find(entityClass, id);

            // Double-check tenant isolation at entity level
            if (entity != null && entity instanceof TenantAware) {
                String entityTenant = ((TenantAware) entity).getTenantId();
                if (!entityTenant.equals(targetTenantId)) {
                    auditLogger.error("TENANT_MISMATCH|entity={}|id={}|expected={}|actual={}",
                        entityClass.getSimpleName(), id, targetTenantId, entityTenant);
                    throw new TenantIsolationViolationException("Tenant isolation breach detected");
                }
            }

            return Optional.ofNullable(entity);
        } finally {
            session.disableFilter("tenantFilter");
        }
    }
}

/**
 * Database-level row security (PostgreSQL RLS integration)
 */
public class DatabaseTenantContext {

    public void setTenantContext(Connection conn, String tenantId) throws SQLException {
        // Set session variable for PostgreSQL Row Level Security
        try (PreparedStatement stmt = conn.prepareStatement(
                "SET app.current_tenant = ?")) {
            stmt.setString(1, tenantId);
            stmt.execute();
        }
    }
}
```

