import (
	"database/sql"
	"encoding/json"
	"net/http"
	"strconv"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

var db *sql.DB

type Customer struct {
	ID       int    `json:"id"`
	TenantID int    `json:"tenant_id"`
	Name     string `json:"name"`
	Email    string `json:"email"`
	SSN      string `json:"ssn"`
}

// VULNERABLE: Gets customer by ID without tenant validation
func getCustomer(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	customerID := vars["id"]

	// Tenant ID from JWT token (user's organization)
	tenantID := r.Context().Value("tenant_id").(int)
	_ = tenantID // IGNORED! Not used in query

	// DANGEROUS: No tenant isolation - any customer ID returns data
	query := "SELECT id, tenant_id, name, email, ssn FROM customers WHERE id = $1"
	row := db.QueryRow(query, customerID)

	var customer Customer
	err := row.Scan(&customer.ID, &customer.TenantID, &customer.Name, &customer.Email, &customer.SSN)
	if err != nil {
		http.Error(w, "Customer not found", http.StatusNotFound)
		return
	}

	json.NewEncoder(w).Encode(customer)
}

// VULNERABLE: Lists all customers with client-controlled tenant filter
func listCustomers(w http.ResponseWriter, r *http.Request) {
	// DANGEROUS: Tenant ID from query parameter instead of authenticated context
	tenantIDParam := r.URL.Query().Get("tenant_id")
	tenantID, _ := strconv.Atoi(tenantIDParam)

	query := "SELECT id, tenant_id, name, email, ssn FROM customers WHERE tenant_id = $1"
	rows, _ := db.Query(query, tenantID)
	defer rows.Close()

	var customers []Customer
	for rows.Next() {
		var c Customer
		rows.Scan(&c.ID, &c.TenantID, &c.Name, &c.Email, &c.SSN)
		customers = append(customers, c)
	}

	json.NewEncoder(w).Encode(customers)
