// TenantIsolationMiddleware extracts and validates tenant from JWT
func TenantIsolationMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Extract tenant from validated JWT (not from user input)
		tenantCtx, err := extractTenantFromJWT(r)
		if err != nil {
			log.Printf("SECURITY: Invalid tenant context from %s", r.RemoteAddr)
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		ctx := context.WithValue(r.Context(), "tenant", tenantCtx)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

// SECURE: Always enforces tenant boundary in query
func getCustomer(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	customerID := vars["id"]

	// Get tenant from authenticated context (NOT user input)
	tenantCtx := r.Context().Value("tenant").(TenantContext)

	// SECURE: Query ALWAYS includes tenant_id condition
	query := `
		SELECT id, name, email 
		FROM customers 
		WHERE id = $1 AND tenant_id = $2
	`
	row := db.QueryRow(query, customerID, tenantCtx.TenantID)

	var customer Customer
	err := row.Scan(&customer.ID, &customer.Name, &customer.Email)
	if err == sql.ErrNoRows {
		// Log potential attack - resource exists but not for this tenant
		log.Printf("SECURITY: Tenant %d attempted access to customer %s",
			tenantCtx.TenantID, customerID)
		http.Error(w, "Customer not found", http.StatusNotFound)
		return
