**Key Security Controls**:
- **Tenant from auth context only**: Tenant ID extracted from validated JWT, never from user-controlled parameters
- **Mandatory tenant filter**: Every query includes `AND tenant_id = $tenant` condition
- **Sensitive data exclusion**: SSN and other sensitive fields not included in API responses
- **Security logging**: Potential cross-tenant access attempts are logged for monitoring

Excellent question. Production multi-tenant systems need multiple isolation layers: row-level security at the database, cryptographic tenant binding, and careful handling of shared resources.

**PRODUCTION PATTERN**:

```go
package tenant

import (
	"context"
	"crypto/hmac"
	"crypto/sha256"
	"database/sql"
	"encoding/hex"
	"errors"
	"fmt"
	"log/slog"
	"net/http"
	"time"

	"github.com/golang-jwt/jwt/v5"
	_ "github.com/lib/pq"
)

var (
	ErrTenantMismatch     = errors.New("tenant context mismatch")
	ErrInvalidTenantToken = errors.New("invalid tenant token")
)

// TenantContext with cryptographic binding
type TenantContext struct {
	TenantID     int
	TenantUUID   string
	UserID       int
	Role         string
	Permissions  []string
	SessionToken string // HMAC-bound session
	IssuedAt     time.Time
}

// TenantAwareDB wraps database with mandatory tenant isolation
type TenantAwareDB struct {
	db           *sql.DB
	secretKey    []byte
	auditLogger  *slog.Logger
}

func NewTenantAwareDB(db *sql.DB, secretKey []byte, logger *slog.Logger) *TenantAwareDB {
	return &TenantAwareDB{
		db:          db,
		secretKey:   secretKey,
		auditLogger: logger,
	}
}

// SetTenantContext configures PostgreSQL Row-Level Security for current connection
func (tdb *TenantAwareDB) SetTenantContext(ctx context.Context, tenantCtx TenantContext) (*sql.Conn, error) {
	// Validate cryptographic tenant binding
	if !tdb.validateTenantBinding(tenantCtx) {
		tdb.auditLogger.Error("SECURITY: Tenant binding validation failed",
			"tenant_id", tenantCtx.TenantID,
			"user_id", tenantCtx.UserID,
		)
		return nil, ErrInvalidTenantToken
	}

	// Get dedicated connection for this request
	conn, err := tdb.db.Conn(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed to get connection: %w", err)
	}

	// Set PostgreSQL session variable for Row-Level Security
	// RLS policies reference this variable to filter all queries
	_, err = conn.ExecContext(ctx,
		"SET app.current_tenant_id = $1",
		tenantCtx.TenantID,
	)
	if err != nil {
		conn.Close()
		return nil, fmt.Errorf("failed to set tenant context: %w", err)
	}

	// Audit log for compliance
	tdb.auditLogger.Info("Tenant context established",
		"tenant_id", tenantCtx.TenantID,
		"user_id", tenantCtx.UserID,
		"role", tenantCtx.Role,
	)

	return conn, nil
}

// validateTenantBinding verifies HMAC signature on tenant context
func (tdb *TenantAwareDB) validateTenantBinding(ctx TenantContext) bool {
	expectedToken := tdb.generateTenantToken(ctx.TenantID, ctx.UserID, ctx.IssuedAt)
	return hmac.Equal([]byte(ctx.SessionToken), []byte(expectedToken))
}

func (tdb *TenantAwareDB) generateTenantToken(tenantID, userID int, issuedAt time.Time) string {
	mac := hmac.New(sha256.New, tdb.secretKey)
	mac.Write([]byte(fmt.Sprintf("%d:%d:%d", tenantID, userID, issuedAt.Unix())))
	return hex.EncodeToString(mac.Sum(nil))
}

// TenantRepository with enforced isolation
type TenantRepository struct {
	tdb *TenantAwareDB
}

type Customer struct {
	ID        int       `json:"id"`
	TenantID  int       `json:"-"` // Never expose in API
	Name      string    `json:"name"`
	Email     string    `json:"email"`
	CreatedAt time.Time `json:"created_at"`
}

// GetCustomer with defense-in-depth tenant validation
func (repo *TenantRepository) GetCustomer(ctx context.Context, tenantCtx TenantContext, customerID int) (*Customer, error) {
	// Layer 1: Set RLS context at database level
	conn, err := repo.tdb.SetTenantContext(ctx, tenantCtx)
	if err != nil {
		return nil, err
	}
	defer conn.Close()

	// Layer 2: Explicit tenant filter in query (defense in depth)
	// Even if RLS fails, this query won't return cross-tenant data
	query := `
		SELECT id, tenant_id, name, email, created_at
		FROM customers
		WHERE id = $1 AND tenant_id = $2
	`

	var customer Customer
	err = conn.QueryRowContext(ctx, query, customerID, tenantCtx.TenantID).Scan(
		&customer.ID,
		&customer.TenantID,
		&customer.Name,
		&customer.Email,
		&customer.CreatedAt,
	)

	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("query error: %w", err)
	}

	// Layer 3: Post-query validation (belt and suspenders)
	if customer.TenantID != tenantCtx.TenantID {
		repo.tdb.auditLogger.Error("CRITICAL: Cross-tenant data leak prevented",
			"requested_tenant", tenantCtx.TenantID,
			"data_tenant", customer.TenantID,
			"customer_id", customerID,
		)
		return nil, ErrTenantMismatch
	}

	return &customer, nil
}

// SharedResourceAccess handles resources accessible across tenants with explicit grants
type SharedResourceAccess struct {
	tdb *TenantAwareDB
}

type SharedDocument struct {
	ID          int    `json:"id"`
	OwnerTenant int    `json:"owner_tenant"`
	Title       string `json:"title"`
}

// GetSharedDocument with explicit access grant verification
func (sra *SharedResourceAccess) GetSharedDocument(ctx context.Context, tenantCtx TenantContext, docID int) (*SharedDocument, error) {
	conn, err := sra.tdb.SetTenantContext(ctx, tenantCtx)
	if err != nil {
		return nil, err
	}
	defer conn.Close()

	// Query checks EITHER ownership OR explicit sharing grant
	query := `
		SELECT d.id, d.owner_tenant_id, d.title
		FROM documents d
		WHERE d.id = $1
		AND (
			d.owner_tenant_id = $2
			OR EXISTS (
				SELECT 1 FROM document_shares ds
				WHERE ds.document_id = d.id
				AND ds.shared_with_tenant_id = $2
				AND ds.expires_at > NOW()
				AND ds.revoked = false
			)
		)
	`

	var doc SharedDocument
	err = conn.QueryRowContext(ctx, query, docID, tenantCtx.TenantID).Scan(
		&doc.ID,
		&doc.OwnerTenant,
		&doc.Title,
	)

	if err == sql.ErrNoRows {
		sra.tdb.auditLogger.Warn("Shared document access denied",
			"tenant_id", tenantCtx.TenantID,
			"document_id", docID,
		)
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("query error: %w", err)
	}

	sra.tdb.auditLogger.Info("Shared document accessed",
		"accessing_tenant", tenantCtx.TenantID,
		"document_id", docID,
		"owner_tenant", doc.OwnerTenant,
	)

	return &doc, nil
}

// TenantIsolationMiddleware for distributed systems
func TenantIsolationMiddleware(tdb *TenantAwareDB, jwtSecret []byte) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Extract and validate JWT
			tenantCtx, err := extractAndValidateTenantJWT(r, jwtSecret, tdb)
			if err != nil {
				tdb.auditLogger.Error("SECURITY: JWT validation failed",
					"error", err.Error(),
					"remote_addr", r.RemoteAddr,
					"path", r.URL.Path,
				)
				http.Error(w, "Unauthorized", http.StatusUnauthorized)
				return
			}

			// Verify tenant still exists and is active
			if !verifyTenantActive(r.Context(), tdb.db, tenantCtx.TenantID) {
				tdb.auditLogger.Warn("Access attempt for inactive tenant",
					"tenant_id", tenantCtx.TenantID,
				)
				http.Error(w, "Tenant suspended", http.StatusForbidden)
				return
			}

			ctx := context.WithValue(r.Context(), "tenant_context", tenantCtx)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

func extractAndValidateTenantJWT(r *http.Request, secret []byte, tdb *TenantAwareDB) (TenantContext, error) {
	tokenString := r.Header.Get("Authorization")
	if len(tokenString) < 8 {
		return TenantContext{}, errors.New("missing authorization header")
	}
	tokenString = tokenString[7:] // Remove "Bearer "

	token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
		if _, ok := token.Method.(*jwt.SigningMethodHMAC); !ok {
			return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
		}
		return secret, nil
	})

	if err != nil || !token.Valid {
		return TenantContext{}, errors.New("invalid token")
	}

	claims, ok := token.Claims.(jwt.MapClaims)
	if !ok {
		return TenantContext{}, errors.New("invalid claims")
	}

	tenantID := int(claims["tenant_id"].(float64))
	userID := int(claims["user_id"].(float64))
	issuedAt := time.Unix(int64(claims["iat"].(float64)), 0)

	tctx := TenantContext{
		TenantID:     tenantID,
		TenantUUID:   claims["tenant_uuid"].(string),
		UserID:       userID,
		Role:         claims["role"].(string),
		IssuedAt:     issuedAt,
		SessionToken: tdb.generateTenantToken(tenantID, userID, issuedAt),
	}

	return tctx, nil
}

func verifyTenantActive(ctx context.Context, db *sql.DB, tenantID int) bool {
	var active bool
	err := db.QueryRowContext(ctx,
		"SELECT is_active FROM tenants WHERE id = $1",
		tenantID,
	).Scan(&active)
	return err == nil && active
}
```

**PostgreSQL Row-Level Security Setup**:

```sql
-- Enable RLS on tables
ALTER TABLE customers ENABLE ROW LEVEL SECURITY;
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE documents ENABLE ROW LEVEL SECURITY;

-- Create policy that uses session variable
CREATE POLICY tenant_isolation ON customers
    FOR ALL
    USING (tenant_id = current_setting('app.current_tenant_id')::int);

CREATE POLICY tenant_isolation ON orders
    FOR ALL  
    USING (tenant_id = current_setting('app.current_tenant_id')::int);

-- Force RLS even for table owners
ALTER TABLE customers FORCE ROW LEVEL SECURITY;
ALTER TABLE orders FORCE ROW LEVEL SECURITY;
```

**Defense in Depth Layers**:

1. **Database-Level RLS**: PostgreSQL Row-Level Security automatically filters ALL queries based on session tenant variable - even if application code has bugs, wrong data cannot be returned

2. **Application-Level Filtering**: Explicit `AND tenant_id = $tenant` in every query provides redundancy if RLS is misconfigured

3. **Post-Query Validation**: Final check after data retrieval catches any edge cases where isolation failed

4. **Cryptographic Session Binding**: HMAC-signed tenant tokens prevent tampering with tenant context in distributed systems

**Additional Protections**:
- **Tenant suspension checks**: Verify tenant is active before processing requests
- **Shared resource grants**: Explicit, time-limited, revocable grants for cross-tenant access
- **Comprehensive audit logging**: Every tenant context switch and cross-tenant access attempt logged
- **Connection isolation**: Dedicated database connections per request with tenant context set at connection level
- **UUIDs for external references**: Use tenant UUIDs instead of sequential IDs to prevent enumeration
